import React from "react";
import { Dumbbell, Plus } from "lucide-react";

export function WorkoutsPage() {
  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <h1 className="text-2xl font-bold text-white">Workouts Database</h1>
        <button className="bg-[#39FF14] text-black px-6 py-3 rounded-lg font-bold flex items-center gap-2">
          <Plus size={20} /> Add Workout
        </button>
      </div>
      <div className="bg-[#1a1a1a] border border-[#2a2a2a] rounded-xl p-20 flex flex-col items-center text-center">
        <Dumbbell className="w-16 h-16 text-[#39FF14] mb-4 opacity-20" />
        <h2 className="text-xl font-bold text-white">Exercise Library</h2>
        <p className="text-gray-400 max-w-xs mt-2">Manage your gym's workout programs here.</p>
      </div>
    </div>
  );
}
